#include <bits/stdc++.h>
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=5e2+5,dx[]={0,0,1,-1},dy[]={1,-1,0,0};
int n,m,a,b,x,y,vis[MAXN][MAXN],t[MAXN][MAXN];
queue<PII>q;
void bfs()
{
	t[x][y]=0;
	vis[x][y]=1;
	wh(!q.empty())
	{
		PII f=q.front();
		q.pop();
		int x=f.fst,y=f.snd;
		FOR(i,0,3)
		{
			int tx=x+dx[i],ty=y+dy[i];
			if(tx<1||ty<1||tx>n||ty>m||vis[tx][ty])continue;
			vis[tx][ty]=1;
			t[tx][ty]=min(t[x][y]+1,t[tx][ty]);
			q.push(mk(tx,ty));
		}
	}
}
int main(void)
{
	memset(t,0x3f,sizeof t );
	memset(vis,false,sizeof vis );
	n=read(),m=read(),a=read(),b=read();
	for(int i=1;i<=a;i++){
		cin>>x>>y;
        q.push(mk(x,y));
		t[x][y]=0;
	}
    bfs();
	FOR(i,1,b)
	{
		x=read(),y=read();
		writeln(t[x][y]);
	}
	return false;
}
